class SecurityManager(private val context: Context) {

    companion object {
        private const val KEYSTORE_ALIAS = "PaymentKeyAlias"
        private const val ANDROID_KEYSTORE = "AndroidKeyStore"
        private const val AES_GCM_NOPADDING = "AES/GCM/NoPadding"
        private const val GCM_TAG_LENGTH = 128
        private const val GCM_IV_LENGTH = 12
        private const val FALLBACK_KEY_PREF = "fallback_key_store"
        private const val TAG = "SecurityManager"
    }

    private val useAndroidKeystore: Boolean = Build.VERSION.SDK_INT >= Build.VERSION_CODES.M

    init {
        if (useAndroidKeystore) {
            createKeyInAndroidKeystore()
        }
    }

    private fun createKeyInAndroidKeystore() {
        try {
            val keyStore = KeyStore.getInstance(ANDROID_KEYSTORE)
            keyStore.load(null)
            if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
                    val keyGenerator = KeyGenerator.getInstance(
                        KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE
                    )
                    val spec = KeyGenParameterSpec.Builder(
                        KEYSTORE_ALIAS,
                        KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                    )
                        .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                        .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                        .setKeySize(256)
                        .setRandomizedEncryptionRequired(true)
                        .build()
                    keyGenerator.init(spec)
                    keyGenerator.generateKey()
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "Failed to create key in Android Keystore", e)
        }
    }

    private fun getSecretKey(): SecretKey {
        return if (useAndroidKeystore) {
            try {
                val keyStore = KeyStore.getInstance(ANDROID_KEYSTORE)
                keyStore.load(null)
                (keyStore.getEntry(KEYSTORE_ALIAS, null) as KeyStore.SecretKeyEntry).secretKey
            } catch (e: Exception) {
                Log.w(TAG, "Falling back to software key", e)
                getFallbackKey()
            }
        } else {
            getFallbackKey()
        }
    }

    private fun getFallbackKey(): SecretKey {
        val prefs = context.getSharedPreferences(FALLBACK_KEY_PREF, Context.MODE_PRIVATE)
        val existingKey = prefs.getString("enc_key", null)
        return if (existingKey != null) {
            val keyBytes = Base64.decode(existingKey, Base64.NO_WRAP)
            SecretKeySpec(keyBytes, "AES")
        } else {
            val keyGen = KeyGenerator.getInstance("AES")
            keyGen.init(256, SecureRandom())
            val key = keyGen.generateKey()
            prefs.edit().putString("enc_key", Base64.encodeToString(key.encoded, Base64.NO_WRAP)).apply()
            key
        }
    }

    fun encrypt(plainText: String): String {
        return try {
            val cipher = Cipher.getInstance(AES_GCM_NOPADDING)
            cipher.init(Cipher.ENCRYPT_MODE, getSecretKey())
            val iv = cipher.iv
            val encryptedBytes = cipher.doFinal(plainText.toByteArray(Charsets.UTF_8))
            val combined = ByteArray(iv.size + encryptedBytes.size)
            System.arraycopy(iv, 0, combined, 0, iv.size)
            System.arraycopy(encryptedBytes, 0, combined, iv.size, encryptedBytes.size)
            Base64.encodeToString(combined, Base64.NO_WRAP)
        } catch (e: Exception) {
            Log.e(TAG, "Encryption failed", e)
            throw SecurityException("Failed to encrypt data", e)
        }
    }

    fun decrypt(encryptedText: String): String {
        return try {
            val combined = Base64.decode(encryptedText, Base64.NO_WRAP)
            val iv = combined.copyOfRange(0, GCM_IV_LENGTH)
            val encryptedBytes = combined.copyOfRange(GCM_IV_LENGTH, combined.size)
            val cipher = Cipher.getInstance(AES_GCM_NOPADDING)
            val spec = GCMParameterSpec(GCM_TAG_LENGTH, iv)
            cipher.init(Cipher.DECRYPT_MODE, getSecretKey(), spec)
            String(cipher.doFinal(encryptedBytes), Charsets.UTF_8)
        } catch (e: Exception) {
            Log.e(TAG, "Decryption failed", e)
            throw SecurityException("Failed to decrypt data", e)
        }
    }

    fun hashData(data: String): String {
        val salt = generateSalt()
        val digest = MessageDigest.getInstance("SHA-256")
        digest.update(salt)
        val hash = digest.digest(data.toByteArray(Charsets.UTF_8))
        val saltAndHash = ByteArray(salt.size + hash.size)
        System.arraycopy(salt, 0, saltAndHash, 0, salt.size)
        System.arraycopy(hash, 0, saltAndHash, salt.size, hash.size)
        return Base64.encodeToString(saltAndHash, Base64.NO_WRAP)
    }

    private fun generateSalt(): ByteArray {
        val salt = ByteArray(16)
        SecureRandom().nextBytes(salt)
        return salt
    }

    fun generateTransactionId(): String {
        val random = ByteArray(16)
        SecureRandom().nextBytes(random)
        return UUID.nameUUIDFromBytes(random).toString()
    }
}

